SELECT COUNT(*) FROM app_admin_account
AND (username LIKE CONCAT('%', #{keyword}, '%') OR nick_name LIKE CONCAT('%', #{keyword}, '%'))
AND status = #{status}

SELECT a.id, a.username, a.nick_name AS nickName, a.status, a.built_in AS builtIn, a.must_reset_password AS mustResetPassword, a.last_login_at AS lastLoginAt, a.last_login_ip AS lastLoginIp, a.remark, a.created_at AS createdAt, a.updated_at AS updatedAt, GROUP_CONCAT(r.role_name ORDER BY r.sort_order ASC SEPARATOR ', ') AS roleNames, GROUP_CONCAT(r.role_key ORDER BY r.sort_order ASC SEPARATOR ',') AS roleKeys FROM app_admin_account a LEFT JOIN app_admin_account_role ar ON ar.account_id = a.id LEFT JOIN app_admin_role r ON r.id = ar.role_id
AND (a.username LIKE CONCAT('%', #{keyword}, '%') OR a.nick_name LIKE CONCAT('%', #{keyword}, '%'))
AND a.status = #{status}
GROUP BY a.id ORDER BY a.id DESC LIMIT #{limit} OFFSET #{offset}

